export const generateNifty500 = () => {
  // Deduplicate by symbol
  const seen = new Set();
  return STOCKS.filter(s => {
    if (seen.has(s.symbol)) return false;
    seen.add(s.symbol);
    return true;
  }).map(s => ({
    ...s,
    change: (((s.price - s.prevClose) / s.prevClose) * 100).toFixed(2),
    outlook: parseFloat(s.pe) < 15 ? "Value" : parseFloat(s.pe) < 25 ? "Stable" : parseFloat(s.pe) < 50 ? "Growth" : "Speculative",
    health:  parseFloat(s.pb) < 2 ? 6 : parseFloat(s.pb) < 5 ? 8 : 9,
    plan:    `Strategic expansion and market share growth in the ${s.sector} sector.`,
    policy:  `Government PLI and regulatory support for the ${s.sector} segment.`,
    geo:     `Global ${s.sector.toLowerCase()} supply chain and geopolitical factors affecting operations.`
  }));
};
